-- =============================================================
-- Mise a jour catalogue (categorie Laptop + modeles) + inventaire IT
-- Genere depuis INVENTAIRE_IT.csv. A lancer dans Supabase -> SQL Editor.
-- =============================================================
BEGIN;

-- 1) Categorie Laptop

-- 2) Modeles de laptop dans le catalogue
SELECT v.name, c.id, v.stock, v.descr, true
FROM (VALUES
  ('HP Elite Book 650 G9', 5, 'Laptop HP Elite Book 650 G9'),
  ('HP ProBook 4 G1iR 16"', 5, 'Laptop HP ProBook 4 G1iR 16"'),
  ('MacBook Air 13" - M1', 5, 'Laptop MacBook Air 13" - M1'),
  ('MacBook Air 13" - M2', 25, 'Laptop MacBook Air 13" - M2'),
  ('MacBook Air 13" - M3', 3, 'Laptop MacBook Air 13" - M3'),
  ('MacBook Air 13" - M4', 5, 'Laptop MacBook Air 13" - M4'),
  ('MacBook Pro M3 - 14"', 1, 'Laptop MacBook Pro M3 - 14"'),
  ('MacBook Pro M4 MAX', 3, 'Laptop MacBook Pro M4 MAX'),
  ('MacBook Pro M4 Pro - 14"', 3, 'Laptop MacBook Pro M4 Pro - 14"'),
  ('HP Probook 450 G6', 1, 'Laptop HP Probook 450 G6'),
  ('HP Probook 450 G8', 13, 'Laptop HP Probook 450 G8')
) AS v(name, stock, descr)
CROSS JOIN (SELECT id FROM categories WHERE name='Laptop') c
WHERE NOT EXISTS (SELECT 1 FROM products p WHERE p.name = v.name);

-- 3) Rafraichir l'inventaire IT (remplace tout par la liste a jour)
TRUNCATE TABLE it_inventory_items;

COMMIT;